// ─── Brand animation system: F1-S · O3-G · F1-R ─────────────────────────────
const ANIM_COLORS = {
  slow:   { main:[139,92,246],  glow:[139,92,246],  bg:[8,4,20]   },
  ground: { main:[59,130,246],  glow:[59,130,246],  bg:[3,6,20]   },
  rise:   { main:[236,72,153],  glow:[236,72,153],  bg:[18,3,10]  },
  smoke:  { main:[200,200,210], glow:[180,180,200], bg:[4,4,6]    },
  pink:   { main:[230,60,255],  glow:[210,40,240],  bg:[10,3,18]  },
  violet: { main:[180,80,255],  glow:[160,60,230],  bg:[6,3,20]   },
  green:  { main:[60,220,100],  glow:[40,190,80],   bg:[3,15,7]   },
  teal:   { main:[40,210,130],  glow:[20,180,100],  bg:[3,14,10]  },
};

// helper: draw tinted background
function _animBg(ctx, W, H, col) {
  const [r,g,b] = col.bg;
  const bg = ctx.createRadialGradient(W/2,H/2,0,W/2,H/2,Math.min(W,H)*0.72);
  bg.addColorStop(0, `rgba(${r+18},${g+14},${b+18},1)`);
  bg.addColorStop(1, `rgb(${r},${g},${b})`);
  ctx.fillStyle = bg; ctx.fillRect(0,0,W,H);
}

// F1-S: Flower Bloom Slow — 2 intersecting circles, breathes
function drawF1S(ctx, W, H, col, T) {
  ctx.clearRect(0,0,W,H); _animBg(ctx,W,H,col);
  const cx=W/2,cy=H/2,S=Math.min(W,H);
  const [mr,mg,mb]=col.main;
  const breathe = 1 + 0.07*Math.sin(T*0.38);
  const R = S*0.24*breathe;
  const rot = T*0.07;
  ctx.globalCompositeOperation='lighter';
  const pairs = [[0,0],[1,0]]; // center + 1 petal
  pairs.forEach(([pi],i) => {
    const a = rot + pi*(Math.PI*2/1);
    const px = i===0 ? cx : cx+Math.cos(a)*R;
    const py = i===0 ? cy : cy+Math.sin(a)*R;
    const pulse = 0.8+0.2*Math.sin(T*0.45+i*1.2);
    // glow halo
    const g = ctx.createRadialGradient(px,py,0,px,py,R*1.4);
    g.addColorStop(0,`rgba(${mr},${mg},${mb},${0.18*pulse})`);
    g.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=g; ctx.fillRect(0,0,W,H);
    // ring
    ctx.beginPath(); ctx.arc(px,py,R,0,Math.PI*2);
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${0.12*pulse})`;
    ctx.lineWidth=S*0.025; ctx.stroke();
    ctx.beginPath(); ctx.arc(px,py,R,0,Math.PI*2);
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${0.65*pulse})`;
    ctx.lineWidth=S*0.008; ctx.stroke();
  });
  // hot core
  const cg = ctx.createRadialGradient(cx,cy,0,cx,cy,R*0.35);
  cg.addColorStop(0,'rgba(255,255,255,0.85)');
  cg.addColorStop(0.4,`rgba(${mr},${mg},${mb},0.5)`);
  cg.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=cg; ctx.fillRect(0,0,W,H);
  ctx.globalCompositeOperation='source-over';
  // edge vignette
  const ev=ctx.createRadialGradient(cx,cy,S*0.32,cx,cy,S*0.52);
  const [br,bg2,bb]=col.bg;
  ev.addColorStop(0,'rgba(0,0,0,0)'); ev.addColorStop(1,`rgba(${br},${bg2},${bb},0.95)`);
  ctx.fillStyle=ev; ctx.fillRect(0,0,W,H);
}

// F1-R: Flower Bloom Rise — 6 petals + outer ring, energetic
function drawF1R(ctx, W, H, col, T) {
  ctx.clearRect(0,0,W,H); _animBg(ctx,W,H,col);
  const cx=W/2,cy=H/2,S=Math.min(W,H);
  const [mr,mg,mb]=col.main;
  const breathe = 1+0.06*Math.sin(T*0.55);
  const R = S*0.21*breathe;
  const rot = T*0.12;
  ctx.globalCompositeOperation='lighter';
  // center
  [[0,0],...Array.from({length:6},(_,i)=>[i])].forEach(([pi],idx) => {
    const a = rot + (idx===0 ? 0 : (pi/6)*Math.PI*2);
    const px = idx===0 ? cx : cx+Math.cos(a)*R;
    const py = idx===0 ? cy : cy+Math.sin(a)*R;
    const pulse = 0.75+0.25*Math.sin(T*0.5+idx*0.8);
    const g=ctx.createRadialGradient(px,py,0,px,py,R*1.3);
    g.addColorStop(0,`rgba(${mr},${mg},${mb},${0.15*pulse})`);
    g.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=g; ctx.fillRect(0,0,W,H);
    ctx.beginPath(); ctx.arc(px,py,R,0,Math.PI*2);
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${0.10*pulse})`;
    ctx.lineWidth=S*0.022; ctx.stroke();
    ctx.beginPath(); ctx.arc(px,py,R,0,Math.PI*2);
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${0.65*pulse})`;
    ctx.lineWidth=S*0.007; ctx.stroke();
  });
  // outer ring of 6 at R*2
  Array.from({length:6},(_,i)=>{
    const a=rot*0.7+(i/6)*Math.PI*2;
    const px=cx+Math.cos(a)*R*2, py=cy+Math.sin(a)*R*2;
    const pulse=0.5+0.2*Math.sin(T*0.4+i);
    ctx.beginPath(); ctx.arc(px,py,R,0,Math.PI*2);
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${0.25*pulse})`;
    ctx.lineWidth=S*0.005; ctx.stroke();
  });
  // core
  const cg=ctx.createRadialGradient(cx,cy,0,cx,cy,R*0.3);
  cg.addColorStop(0,'rgba(255,255,255,0.92)');
  cg.addColorStop(0.3,`rgba(${mr},${mg},${mb},0.6)`);
  cg.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=cg; ctx.fillRect(0,0,W,H);
  ctx.globalCompositeOperation='source-over';
  const [br,bg2,bb]=col.bg;
  const ev=ctx.createRadialGradient(cx,cy,S*0.38,cx,cy,S*0.54);
  ev.addColorStop(0,'rgba(0,0,0,0)'); ev.addColorStop(1,`rgba(${br},${bg2},${bb},0.95)`);
  ctx.fillStyle=ev; ctx.fillRect(0,0,W,H);
}

// O3-G: Organic Circle Ground — deforming circle, stable
function drawO3G(ctx, W, H, col, T) {
  ctx.clearRect(0,0,W,H); _animBg(ctx,W,H,col);
  const cx=W/2,cy=H/2,S=Math.min(W,H);
  const [mr,mg,mb]=col.main;
  const breathe=1+0.08*Math.sin(T*0.42);
  const R=S*0.3*breathe;
  ctx.globalCompositeOperation='lighter';
  [0,1].forEach(layer => {
    const pts=40, rLayer=R*(layer===0?1:0.72);
    const amp=S*(layer===0?0.038:0.022);
    const spd=layer===0?0.28:0.35;
    ctx.beginPath();
    for(let i=0;i<=pts;i++){
      const a=(i/pts)*Math.PI*2;
      const noise=amp*(Math.sin(3*a+T*spd)+0.5*Math.sin(5*a-T*spd*0.7)+0.3*Math.sin(7*a+T*spd*0.4));
      const r=rLayer+noise;
      const x=cx+Math.cos(a)*r, y=cy+Math.sin(a)*r;
      i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
    }
    ctx.closePath();
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${layer===0?0.08:0.05})`;
    ctx.lineWidth=S*0.025; ctx.stroke();
    ctx.strokeStyle=`rgba(${mr},${mg},${mb},${layer===0?0.7:0.4})`;
    ctx.lineWidth=S*(layer===0?0.009:0.006); ctx.stroke();
    // glow
    const g=ctx.createRadialGradient(cx,cy,0,cx,cy,rLayer);
    g.addColorStop(0,`rgba(${mr},${mg},${mb},0.08)`);
    g.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=g; ctx.fillRect(0,0,W,H);
  });
  // core
  const cg=ctx.createRadialGradient(cx,cy,0,cx,cy,R*0.28);
  cg.addColorStop(0,'rgba(255,255,255,0.88)');
  cg.addColorStop(0.3,`rgba(${mr},${mg},${mb},0.45)`);
  cg.addColorStop(1,'rgba(0,0,0,0)');
  ctx.fillStyle=cg; ctx.fillRect(0,0,W,H);
  ctx.globalCompositeOperation='source-over';
  const [br,bg2,bb]=col.bg;
  const ev=ctx.createRadialGradient(cx,cy,R*0.65,cx,cy,S*0.52);
  ev.addColorStop(0,'rgba(0,0,0,0)'); ev.addColorStop(1,`rgba(${br},${bg2},${bb},0.95)`);
  ctx.fillStyle=ev; ctx.fillRect(0,0,W,H);
}

// Dispatch by category
function drawAnimFrame(ctx, W, H, type, T) {
  const col = ANIM_COLORS[type] || ANIM_COLORS.slow;
  if (type === 'ground') drawO3G(ctx, W, H, col, T);
  else if (type === 'rise') drawF1R(ctx, W, H, col, T);
  else drawF1S(ctx, W, H, col, T); // slow + smoke + others
}

// Cache: one offscreen canvas per type+size, each runs its own rAF
const _animCache = {};
function getAnimCanvas(type, size) {
  const key = `${type}_${size}`;
  if (_animCache[key]) return _animCache[key];
  const DPR = 2, S = size * DPR;
  const canvas = document.createElement('canvas');
  canvas.width = S; canvas.height = S;
  const ctx = canvas.getContext('2d');
  function loop(ts) { drawAnimFrame(ctx, S, S, type, ts*0.001); requestAnimationFrame(loop); }
  requestAnimationFrame(loop);
  _animCache[key] = canvas;
  return canvas;
}

const EnergyBlob = ({ type = 'slow', size = 80, radius = 14, play = false, lock = false }) => {
  const ref = useRef(null);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const src = getAnimCanvas(type, size);
    const myCanvas = document.createElement('canvas');
    myCanvas.width = size; myCanvas.height = size;
    myCanvas.style.cssText = `position:absolute;top:0;left:0;width:${size}px;height:${size}px;border-radius:${radius}px`;
    el.style.position = 'relative';
    el.appendChild(myCanvas);
    const myCtx = myCanvas.getContext('2d');
    let raf;
    function copy() { myCtx.drawImage(src,0,0,src.width,src.height,0,0,size,size); raf=requestAnimationFrame(copy); }
    raf = requestAnimationFrame(copy);
    return () => { cancelAnimationFrame(raf); if(el.contains(myCanvas)) el.removeChild(myCanvas); };
  }, [type, size, radius]);
  return (
    <div ref={ref} style={{ width:size, height:size, flexShrink:0, borderRadius:radius, overflow:'hidden', position:'relative', display:'block' }}>
      {play && !lock && (
        <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', zIndex:10, borderRadius:radius }}>
          <div style={{ width:size*0.38, height:size*0.38, borderRadius:'50%', background:'rgba(0,0,0,0.42)', display:'flex', alignItems:'center', justifyContent:'center' }}>
            <svg width={size*0.16} height={size*0.16} viewBox="0 0 12 14"><path d="M1 1.5l10 5-10 5V1.5z" fill="white"/></svg>
          </div>
        </div>
      )}
      {lock && (
        <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.60)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:10, borderRadius:radius }}>
          <svg width="20" height="22" viewBox="0 0 24 24" fill="none" stroke="#C034A5" strokeWidth="2"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>
        </div>
      )}
    </div>
  );
};

