function SplashScreen({ onNav, sel, onSel }) {
  return (
    <div style={{ height:'100%', background:C.bg, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', position:'relative', overflow:'hidden' }}>
      <style>{`
        @keyframes splashBreathe {
          0%,100% { transform: scale(1) translateY(0px); opacity: 1; }
          50%      { transform: scale(1.07) translateY(-4px); opacity: 0.82; }
        }
        @keyframes splashDot {
          0%,100% { opacity: 0.2; transform: scale(0.8); }
          50%      { opacity: 0.7; transform: scale(1.2); }
        }
        @keyframes splashGlow {
          0%,100% { opacity: 1; transform: translate(-50%,-50%) scale(1); }
          50%      { opacity: 1.6; transform: translate(-50%,-50%) scale(1.18); }
        }
      `}</style>

      {/* Breathing glow — same timing as logo */}
      <div style={{ position:'absolute', top:'38%', left:'50%', width:300, height:300, borderRadius:'50%',
        background:'radial-gradient(circle,rgba(139,92,246,0.14) 0%,transparent 70%)',
        animation:'splashGlow 4s cubic-bezier(0.45,0,0.55,1) infinite', pointerEvents:'none' }}/>

      {/* Single container animates as ONE unit — perfectly synchronised */}
      <A id="Splash · логотип" selected={sel} onSelect={onSel}>
        <div style={{
          display:'flex', flexDirection:'column', alignItems:'center',
          animation:'splashBreathe 4s cubic-bezier(0.45,0,0.55,1) infinite',
          transformOrigin:'center center'
        }}>
          <img src={LOGO_RIBS} width={110} style={{ display:'block' }}/>
          <div style={{ fontFamily:F, fontSize:16, fontWeight:600, color:C.white, marginTop:22, letterSpacing:'0.04em' }}>
            badbuddhas
          </div>
          <div style={{ fontFamily:F, fontSize:13, color:C.sub, marginTop:6, letterSpacing:'0.02em' }}>
            [bubbles]
          </div>
        </div>
      </A>

      {/* Loading dots */}
      <A id="Splash · индикатор загрузки" selected={sel} onSelect={onSel}>
        <div style={{ display:'flex', gap:8, marginTop:56 }}>
          {[0,1,2].map(i => (
            <div key={i} style={{ width:5, height:5, borderRadius:'50%', background:C.sub,
              animation:'splashDot 1.4s ease-in-out infinite',
              animationDelay:`${i*0.22}s` }}/>
          ))}
        </div>
      </A>
    </div>
  );
}

