function OnboardingScreen({ onNav, sel, onSel }) {
  const [step, setStep] = useState(0);
  const steps = [
    { blob:2, blobType:'slow', title:'Дышите осознанно', desc:'Практики дыхания для снятия стресса, восстановления энергии и внутреннего баланса', color:C.slow },
    { blob:0, blobType:'ground', title:'Найдите свой темп', desc:'От 5 до 30 минут — выбирайте практику под своё настроение и расписание', color:C.ground },
    { blob:6, blobType:'rise', title:'Практикуйте каждый день', desc:'Серия практик и напоминания помогут сделать дыхание привычкой', color:C.rise },
  ];
  const s = steps[step];
  return (
    <div style={{ height:'100%', background:C.bg, display:'flex', flexDirection:'column' }}>
      <div style={{ display:'flex', justifyContent:'flex-end', padding:'14px 16px' }}>
        <A id="Онбординг · пропустить" selected={sel} onSelect={onSel}>
          <button onClick={() => onNav('home')} style={{ background:'none', border:'none', fontFamily:F, fontSize:13, color:C.sub, cursor:'pointer' }}>Пропустить</button>
        </A>
      </div>
      <A id="Онбординг · иллюстрация" selected={sel} onSelect={onSel}>
        <div style={{ display:'flex', justifyContent:'center', padding:'8px 0 24px' }}>
          <EnergyBlob type={s.blobType || 'slow'} size={280} radius={0}/>
        </div>
      </A>
      <div style={{ flex:1, padding:'0 28px 40px', display:'flex', flexDirection:'column', justifyContent:'space-between' }}>
        <div>
          <A id="Онбординг · прогресс" selected={sel} onSelect={onSel}>
            <div style={{ display:'flex', gap:6, marginBottom:28 }}>
              {steps.map((_,i) => (
                <div key={i} style={{ height:3, borderRadius:2, background: i<=step ? C.text2 : C.border, flex:1, transition:'all 0.3s ease' }}/>
              ))}
            </div>
          </A>
          <A id="Онбординг · заголовок" selected={sel} onSelect={onSel}>
            <div style={{ fontFamily:F, fontSize:28, fontWeight:800, color:C.white, marginBottom:12, lineHeight:1.2 }}>{s.title}</div>
          </A>
          <A id="Онбординг · описание" selected={sel} onSelect={onSel}>
            <div style={{ fontFamily:F, fontSize:15, color:C.sub, lineHeight:1.6 }}>{s.desc}</div>
          </A>
        </div>
        <A id="Онбординг · кнопка" selected={sel} onSelect={onSel}>
          <button onClick={() => step < steps.length - 1 ? setStep(step + 1) : onNav('home')} style={{ width:'100%', fontFamily:F, fontSize:15, fontWeight:700, color:C.bg, background:C.text, border:'none', borderRadius:16, padding:'16px', cursor:'pointer' }}>
            {step < steps.length - 1 ? 'Далее' : 'Начать'}
          </button>
        </A>
      </div>
    </div>
  );
}

