function SettingsScreen({ onNav, sel, onSel }) {
  const [name, setName] = useState('Stas');
  const [lastName, setLastName] = useState('Zakharov');
  const [lang, setLang] = useState('ru'); // 'ru' | 'en'
  const [saved, setSaved] = useState(false);

  const handleSave = () => { setSaved(true); setTimeout(() => setSaved(false), 1800); };

  const inputStyle = {
    background:'none', border:'none', outline:'none',
    fontFamily:F, fontSize:15, color:C.white, width:'100%', padding:0
  };
  const labelStyle = {
    fontFamily:F, fontSize:12, color:C.sub, marginBottom:8, display:'block', opacity:0.7
  };

  return (
    <div style={{ overflowY:'auto', height:'100%', background:C.bg }}>
      {/* Nav bar — back | Настройки | Сохранить */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'14px 16px', borderBottom:`1px solid ${C.border}` }}>
        <A id="Настройки · назад" selected={sel} onSelect={onSel}>
          <button onClick={() => onNav('profile')} style={{ background:'none', border:'none', cursor:'pointer', padding:0 }}><BackIcon/></button>
        </A>
        <A id="Настройки · заголовок" selected={sel} onSelect={onSel}>
          <span style={{ fontFamily:F, fontSize:17, fontWeight:700, color:C.white }}>Настройки</span>
        </A>
        <A id="Настройки · сохранить" selected={sel} onSelect={onSel}>
          <button onClick={handleSave} style={{ background:'none', border:'none', cursor:'pointer', fontFamily:F, fontSize:14, fontWeight:500, color: saved ? C.green : C.sub, padding:'4px 0' }}>
            {saved ? 'Сохранено' : 'Сохранить'}
          </button>
        </A>
      </div>

      <div style={{ padding:'24px 16px', display:'flex', flexDirection:'column', gap:22 }}>

        {/* Имя */}
        <A id="Настройки · поле имени" selected={sel} onSelect={onSel}>
          <div>
            <span style={labelStyle}>Имя</span>
            <div style={{ background:C.card, borderRadius:14, border:`1px solid ${C.border}`, padding:'14px 16px' }}>
              <input value={name} onChange={e => setName(e.target.value)} style={inputStyle} placeholder="Введите имя"/>
            </div>
          </div>
        </A>

        {/* Фамилия */}
        <A id="Настройки · поле фамилии" selected={sel} onSelect={onSel}>
          <div>
            <span style={labelStyle}>Фамилия</span>
            <div style={{ background:C.card, borderRadius:14, border:`1px solid ${C.border}`, padding:'14px 16px' }}>
              <input value={lastName} onChange={e => setLastName(e.target.value)} style={inputStyle} placeholder="Введите фамилию"/>
            </div>
          </div>
        </A>

        {/* Язык — список как в прод */}
        <A id="Настройки · язык" selected={sel} onSelect={onSel}>
          <div>
            <span style={{ ...labelStyle, textTransform:'uppercase', letterSpacing:'0.08em', fontSize:10 }}>ЯЗЫК</span>
            <div style={{ background:C.card, borderRadius:14, border:`1px solid ${C.border}`, overflow:'hidden' }}>
              {[{id:'en', label:'English'}, {id:'ru', label:'Русский'}].map((l, i, arr) => (
                <div key={l.id} onClick={() => setLang(l.id)}
                  style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'14px 16px',
                    borderBottom: i < arr.length-1 ? `1px solid ${C.border}` : 'none', cursor:'pointer' }}>
                  <span style={{ fontFamily:F, fontSize:15, color:C.white }}>{l.label}</span>
                  {lang === l.id
                    ? <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={C.green} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12"/></svg>
                    : <div style={{ width:18 }}/>
                  }
                </div>
              ))}
            </div>
          </div>
        </A>
      </div>
    </div>
  );
}

