/* ══════════════════════════════════════════
   MAIN SHELL — persistent tab bar for free users
   Tabs: Главная · Каталог · Избранное · Профиль
══════════════════════════════════════════ */
function MainShell({ onNav, sel, onSel }) {
  const [tab, setTab] = useState('home');

  const TABS = [
    { id:'home',      label:'Главная',   icon:(c) => <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={c} strokeWidth="1.8"><path d="M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg> },
    { id:'catalog',   label:'Каталог',   icon:(c) => <MusicIcon color={c} size={20}/> },
    { id:'theory',    label:'Теория',    icon:(c) => <BookIcon color={c} size={20}/> },
    { id:'favorites', label:'Избранное', icon:(c) => <HeartIcon color={c} size={20}/> },
  ];

  // Wrap each screen so its content doesn't overlap the tab bar
  const Wrapped = ({ children }) => (
    <div style={{ height:'calc(100% - 72px)', overflowY:'hidden' }}>{children}</div>
  );

  const screenProps = { onNav: (s) => {
    // Intercept tab-level navigations
    if (['home','catalog','favorites','profile'].includes(s)) { setTab(s); }
    else { onNav(s); }
  }, sel, onSel };

  const CONTENT = {
    home:      <Wrapped><HomeScreen {...screenProps}/></Wrapped>,
    catalog:   <Wrapped><CatalogScreen {...screenProps}/></Wrapped>,
    theory:    <Wrapped><FreeTheoryScreen {...screenProps}/></Wrapped>,
    favorites: <Wrapped><FavoritesScreen {...screenProps}/></Wrapped>,
  };

  return (
    <div style={{ height:'100%', background:C.bg, position:'relative', overflow:'hidden' }}>
      {CONTENT[tab]}

      {/* Persistent floating tab bar */}
      <A id="Таббар · свободный" selected={sel} onSelect={onSel} style={{ position:'absolute', bottom:12, left:12, right:12, zIndex:50 }}>
        <div style={{ background:'rgba(22,22,24,0.97)', backdropFilter:'blur(24px)', WebkitBackdropFilter:'blur(24px)', borderRadius:30, padding:'8px 4px 7px', display:'flex', justifyContent:'space-around', alignItems:'center', boxShadow:'0 4px 32px rgba(0,0,0,0.6), 0 0 0 1px rgba(255,255,255,0.05)' }}>
          {TABS.map(t => {
            const active = tab === t.id;
            const color = active ? C.text : C.sub;
            return (
              <button key={t.id} onClick={() => setTab(t.id)} style={{ background: active ? 'rgba(203,203,203,0.12)' : 'none', border:'none', cursor:'pointer', borderRadius:22, padding:'7px 16px', display:'flex', flexDirection:'column', alignItems:'center', gap:3, transition:'all 0.2s ease' }}>
                {t.icon(color)}
                <span style={{ fontFamily:F, fontSize:9, fontWeight:600, color }}>{t.label}</span>
              </button>
            );
          })}
        </div>
      </A>
    </div>
  );
}


